101	/// Spawn the control channel listener on a Tokio task.
102	///
103	/// Listens on a Unix Domain Socket for commands from the CLI.
104	pub async fn spawn_control_listener(handle: DaemonHandle) -> Result<()> {
105	    let socket_path = get_socket_path()?;
106	
107	    // Clean up existing socket file if it exists
108	    if socket_path.exists() {
109	        std::fs::remove_file(&socket_path)
110	            .with_context(|| format!("Failed to remove existing socket: {}", socket_path.display()))?;
111	    }
112	
113	    let listener = UnixListener::bind(&socket_path)
114	        .with_context(|| format!("Failed to bind to UDS socket: {}", socket_path.display()))?;
115	
116	    // Set permissions to 0600 (user only)
117	    #[cfg(unix)]
118	    {
119	        use std::os::unix::fs::PermissionsExt;
120	        std::fs::set_permissions(&socket_path, std::fs::Permissions::from_mode(0o600))?;
121	    }
122	
123	    tracing::info!("Control channel listening on: {}", socket_path.display());
124	
125	    tokio::spawn(async move {
126	        loop {
127	            match listener.accept().await {
128	                Ok((mut stream, _)) => {
129	                    let h = handle.clone();
130	                    tokio::spawn(async move {
131	                        let (reader, mut writer) = stream.split();
132	                        let mut reader = BufReader::new(reader);
133	                        let mut line = String::new();
134	
135	                        if let Ok(n) = reader.read_line(&mut line).await {
136	                            if n == 0 { return; }
137	
138	                            let response = match serde_json::from_str::<ControlRequest>(&line) {
139	                                Ok(req) => {
140	                                    tracing::debug!("Control request: {:?}", req);
141	                                    match req {
142	                                        ControlRequest::Ping => ControlResponse::Pong,
143	                                        ControlRequest::Status => {
144	                                            ControlResponse::StatusData(h.status())
145	                                        }
146	                                        ControlRequest::Mute => {
147	                                            h.muted.store(true, Ordering::Relaxed);
148	                                            tracing::info!("Daemon muted via control socket");
149	                                            ControlResponse::Ok
150	                                        }
151	                                        ControlRequest::Unmute => {
152	                                            h.muted.store(false, Ordering::Relaxed);
153	                                            tracing::info!("Daemon unmuted via control socket");
154	                                            ControlResponse::Ok
155	                                        }
156	                                        ControlRequest::SwitchProfile { name } => {
157	                                            match tokio::task::block_in_place(|| {
158	                                                handle_switch_profile(&name, &h)
159	                                            }) {
160	                                                Ok(_) => ControlResponse::Ok,
161	                                                Err(e) => ControlResponse::Error { message: e.to_string() },
162	                                            }
163	                                        }
164	                                        ControlRequest::Shutdown => {
165	                                            // TODO: wire to CancellationToken in a future slice
166	                                            ControlResponse::Ok
167	                                        }
168	                                        ControlRequest::SetMode { mode } => {
169	                                            *h.active_mode.write().unwrap() = mode.clone();
170	                                            tracing::debug!("SetMode: cached active_mode={mode:?}, forwarding to coordinator");
171	                                            h.send_runtime_cmd(RuntimeCommand::SetMode(mode))
172	                                        }
173	                                        ControlRequest::SetThreshold { threshold } => {
174	                                            h.send_runtime_cmd(RuntimeCommand::SetThreshold(threshold))
175	                                        }
176	                                        ControlRequest::SetInputDevice { device } => {
177	                                            tracing::info!("SetInputDevice received; requires daemon restart (S01 note)");
178	                                            h.send_runtime_cmd(RuntimeCommand::SetInputDevice(device))
179	                                        }
180	                                        ControlRequest::SetPttBinding { key } => {
181	                                            tracing::info!("SetPttBinding received; requires daemon restart (S01 note)");
182	                                            h.send_runtime_cmd(RuntimeCommand::SetPttBinding(key))
183	                                        }
184	                                        ControlRequest::ReloadConfig => {
185	                                            h.send_runtime_cmd(RuntimeCommand::ReloadConfig)
186	                                        }
187	                                        _ => ControlResponse::Error { message: "Not yet implemented".into() },
188	                                    }
189	                                }
190	                                Err(e) => ControlResponse::Error { message: format!("Invalid JSON: {e}") },
191	                            };
192	
193	                            if let Ok(resp_json) = serde_json::to_string(&response) {
194	                                let _ = writer.write_all(resp_json.as_bytes()).await;
195	                                let _ = writer.write_all(b"\n").await;
196	                            }
197	                        }
198	                    });
199	                }
200	                Err(e) => {
201	                    tracing::error!("Control listener accept error: {e}");
202	                }
203	            }
204	        }
205	    });
206	
207	    Ok(())
208	}
209	
210	fn handle_switch_profile(name: &str, handle: &DaemonHandle) -> Result<()> {
211	    use crate::pack::Pack;
212	    use crate::pack::manager::ProfileManager;
213	
214	    let dir = crate::pack::get_profiles_dir()?.join(name);
215	    let pack = Pack::load_from_dir(&dir)?;
216	    handle.dispatcher.update_macros(pack.flatten());
217	
218	    // Track active profile for status queries
219	    *handle.active_profile.write().unwrap() = Some(name.to_string());
220	
221	    // Update persistence so it survives restart
222	    let mut manager = ProfileManager::load().unwrap_or(ProfileManager { active_profile: None });
223	    manager.active_profile = Some(name.to_string());
224	    manager.save()?;
225	
226	    Ok(())
227	}
