192	#[cfg(test)]
193	mod tests {
194	    use super::*;
195	    use crate::config::MacroConfig;
196	
197	    fn make_dispatcher(threshold: f32, phrase: &str) -> Dispatcher {
198	        let (tx, _rx) = std::sync::mpsc::channel();
199	        let macro_cfg = MacroConfig {
200	            name: "eagle_airstrike".to_string(),
201	            phrase: Some(phrase.to_string()),
202	            if_flag: None,
203	            set_flag: None,
204	            sound: None,
205	            keys: vec![],
206	        };
207	        Dispatcher::new(threshold, vec![macro_cfg], tx, 50, 50)
208	    }
209	
210	    #[test]
211	    fn test_update_threshold_changes_match_behavior() {
212	        let dispatcher = make_dispatcher(0.99, "eagle airstrike");
213	        // "eagal airstrike" has distance 1 from "eagle airstrike" (15 chars → score ≈ 0.933)
214	        // Should be below threshold 0.99 → NoMatch
215	        assert!(
216	            matches!(dispatcher.process("eagal airstrike"), DispatchOutcome::NoMatch),
217	            "expected NoMatch at threshold 0.99"
218	        );
219	        // Lower threshold to 0.5 → same input should now Fire
220	        dispatcher.update_threshold(0.5);
221	        assert!(
222	            matches!(
223	                dispatcher.process("eagal airstrike"),
224	                DispatchOutcome::Fired { .. }
225	            ),
226	            "expected Fired at threshold 0.5"
227	        );
228	    }
229	
230	    #[test]
231	    fn test_update_threshold_clamp_negative() {
232	        let dispatcher = make_dispatcher(0.8, "eagle airstrike");
233	        dispatcher.update_threshold(-0.5);
234	        // threshold clamped to 0.0 → everything matches
235	        assert!(matches!(
236	            dispatcher.process("eagle airstrike"),
237	            DispatchOutcome::Fired { .. }
238	        ));
239	    }
240	
241	    #[test]
242	    fn test_update_threshold_clamp_above_one() {
243	        let dispatcher = make_dispatcher(0.8, "eagle airstrike");
244	        dispatcher.update_threshold(2.0);
245	        // threshold clamped to 1.0 → only exact match fires; "eagal" is not exact
246	        assert!(matches!(
247	            dispatcher.process("eagal airstrike"),
248	            DispatchOutcome::NoMatch
249	        ));
250	        // exact input should still fire (score == 1.0 >= 1.0)
251	        assert!(matches!(
252	            dispatcher.process("eagle airstrike"),
253	            DispatchOutcome::Fired { .. }
254	        ));
255	    }
256	
257	    #[test]
258	    fn test_update_threshold_nan_becomes_zero() {
259	        let dispatcher = make_dispatcher(0.8, "eagle airstrike");
260	        dispatcher.update_threshold(f32::NAN);
261	        // threshold clamped to 0.0 → any non-empty transcript with a candidate matches
262	        assert!(matches!(
263	            dispatcher.process("eagle airstrike"),
264	            DispatchOutcome::Fired { .. }
265	        ));
266	    }
267	}
