15	// ── Log channel ──────────────────────────────────────────────────────────────
16	
17	/// A tracing subscriber layer that forwards formatted log records to a channel.
18	struct ChannelLayer {
19	    tx: mpsc::SyncSender<String>,
20	}
21	
22	impl<S> tracing_subscriber::Layer<S> for ChannelLayer
23	where
24	    S: tracing::Subscriber,
25	{
26	    fn on_event(
27	        &self,
28	        event: &tracing::Event<'_>,
29	        _ctx: tracing_subscriber::layer::Context<'_, S>,
30	    ) {
31	        let mut visitor = MessageVisitor(String::new());
32	        event.record(&mut visitor);
33	        let line = format!("[{}] {}", event.metadata().level(), visitor.0);
34	        // Non-blocking send — drop if buffer full to avoid blocking the UI thread.
35	        let _ = self.tx.try_send(line);
36	    }
37	}
38	
39	struct MessageVisitor(String);
40	
41	impl tracing::field::Visit for MessageVisitor {
42	    fn record_str(&mut self, field: &tracing::field::Field, value: &str) {
43	        if field.name() == "message" {
44	            self.0 = value.to_string();
45	        }
46	    }
47	    fn record_debug(&mut self, field: &tracing::field::Field, value: &dyn std::fmt::Debug) {
48	        if field.name() == "message" {
49	            self.0 = format!("{value:?}");
50	        }
51	    }
52	}
53	
54	// ── Mic level thread ─────────────────────────────────────────────────────────
55	
56	/// Shared mic level state: f32 RMS stored as bits in an AtomicU32.
57	struct MicLevelState {
58	    level: Arc<AtomicU32>,
59	    no_device: bool,
60	    _handle: Option<std::thread::JoinHandle<()>>,
61	}
62	
63	impl MicLevelState {
64	    fn current_level(&self) -> f32 {
65	        f32::from_bits(self.level.load(Ordering::Relaxed))
66	    }
67	}
68	
69	fn spawn_mic_level_thread() -> MicLevelState {
70	    let level = Arc::new(AtomicU32::new(0u32));
71	    let level_clone = Arc::clone(&level);
72	
73	    // no_device is signalled back from the thread via a one-shot channel.
74	    let (tx, rx) = std::sync::mpsc::sync_channel::<bool>(1);
75	
76	    // Build and play the stream inside the thread so the !Send stream never
77	    // crosses a thread boundary.
78	    let handle = std::thread::spawn(move || {
79	        use cpal::traits::{DeviceTrait, HostTrait, StreamTrait};
80	
81	        let host = cpal::default_host();
82	        let device = match host.default_input_device() {
83	            Some(d) => d,
84	            None => {
85	                tracing::warn!("Mic level: no default input device found");
86	                let _ = tx.send(true);
87	                return;
88	            }
89	        };
90	
91	        let config = match device.default_input_config() {
92	            Ok(c) => c,
93	            Err(e) => {
94	                tracing::error!(reason = %e, "Mic level: failed to get default input config");
95	                let _ = tx.send(true);
96	                return;
97	            }
98	        };
99	
100	        tracing::info!(
101	            device = device.name().unwrap_or_default(),
102	            sample_rate = config.sample_rate().0,
103	            channels = config.channels(),
104	            "Mic level thread: using device"
105	        );
106	
107	        let err_level = Arc::clone(&level_clone);
108	        let stream_result = device.build_input_stream(
109	            &config.into(),
110	            move |data: &[f32], _| {
111	                if data.is_empty() {
112	                    return;
113	                }
114	                let rms = (data.iter().map(|s| s * s).sum::<f32>() / data.len() as f32).sqrt();
115	                level_clone.store(rms.to_bits(), Ordering::Relaxed);
116	            },
117	            move |e| {
118	                tracing::error!(reason = %e, "Mic level: stream error");
119	                err_level.store(0u32, Ordering::Relaxed);
120	            },
121	            None,
122	        );
123	
124	        let stream = match stream_result {
125	            Ok(s) => s,
126	            Err(e) => {
127	                tracing::error!(reason = %e, "Mic level: failed to build input stream");
128	                let _ = tx.send(true);
129	                return;
130	            }
131	        };
132	
133	        if let Err(e) = stream.play() {
134	            tracing::error!(reason = %e, "Mic level: stream play failed");
135	            let _ = tx.send(true);
136	            return;
137	        }
138	
139	        let _ = tx.send(false);
140	        // Park the thread to keep the stream alive until the process exits.
141	        std::thread::park();
142	    });
143	
144	    let no_device = rx.recv().unwrap_or(true);
145	
146	    MicLevelState {
147	        level,
148	        no_device,
149	        _handle: Some(handle),
150	    }
151	}
