459	fn handle_save(app: &mut VibeAttackConfigApp) {
460	    use vibe_attack::control::client::send_command;
461	    use vibe_attack::control::protocol::ControlRequest;
462	
463	    let Some(cached) = app.cached_config.as_ref() else {
464	        app.config.set_status("No config loaded — cannot save.");
465	        return;
466	    };
467	
468	    match save_app_to_config(&app.config, cached, None) {
469	        Err(e) => {
470	            app.config.set_status(format!("Save failed: {e}"));
471	            return;
472	        }
473	        Ok(updated) => {
474	            app.cached_config = Some(updated);
475	        }
476	    }
477	
478	    if !app.config.daemon_running {
479	        app.config
480	            .set_status("Saved to disk — daemon not running, runtime changes skipped.");
481	        return;
482	    }
483	
484	    // Dispatch four control commands; collect any failures.
485	    let commands = [
486	        ControlRequest::SetMode { mode: app.config.mode.clone() },
487	        ControlRequest::SetThreshold {
488	            threshold: app.config.threshold_pct as f32 / 100.0,
489	        },
490	        ControlRequest::SetInputDevice {
491	            device: app.config.input_device.clone(),
492	        },
493	        ControlRequest::SetPttBinding {
494	            key: app.config.ptt_binding.clone(),
495	        },
496	    ];
497	
498	    let mut errors: Vec<String> = Vec::new();
499	    for cmd in commands {
500	        let label = format!("{cmd:?}");
501	        if let Err(e) = send_command(cmd) {
502	            errors.push(format!("Failed to send {label}: {e}"));
503	        }
504	    }
505	
506	    if errors.is_empty() {
507	        app.config.set_status("Saved and applied.");
508	    } else {
509	        app.config.set_status(errors.join("; "));
510	    }
511	}
