535	/// Build a [`MacroConfig`] from raw form-field strings.
536	///
537	/// - `name` must be non-empty (after trim).
538	/// - `phrase`, `if_flag`, `set_flag` become `None` when empty.
539	/// - `keys` is parsed via [`parse_key_sequence`].
540	///
541	/// This is a pure function with no egui dependency — it is unit-tested directly.
542	pub fn build_macro_config_from_form(
543	    name: &str,
544	    phrase: &str,
545	    if_flag: &str,
546	    set_flag: &str,
547	    keys: &str,
548	) -> Result<MacroConfig, FormBuildError> {
549	    let name = name.trim().to_string();
550	    if name.is_empty() {
551	        return Err(FormBuildError::EmptyName);
552	    }
553	    let phrase = {
554	        let s = phrase.trim();
555	        if s.is_empty() { None } else { Some(s.to_string()) }
556	    };
557	    let if_flag = {
558	        let s = if_flag.trim();
559	        if s.is_empty() { None } else { Some(s.to_string()) }
560	    };
561	    let set_flag = {
562	        let s = set_flag.trim();
563	        if s.is_empty() { None } else { Some(s.to_string()) }
564	    };
565	    let keys = parse_key_sequence(keys).map_err(FormBuildError::KeyParseError)?;
566	
567	    Ok(MacroConfig { name, phrase, if_flag, set_flag, sound: None, keys })
568	}
569	
570	/// Parse a comma-separated key sequence string into a `Vec<KeyAction>`.
571	///
572	/// Each token is trimmed of whitespace and becomes a `KeyAction` with `dwell_ms`
573	/// and `gap_ms` left as `None` (inheriting global timing defaults).
574	/// Returns an error if the input is empty or any token is empty after trimming.
575	pub fn parse_key_sequence(input: &str) -> Result<Vec<KeyAction>> {
576	    if input.trim().is_empty() {
577	        bail!("key sequence must not be empty");
578	    }
579	
580	    let mut actions = Vec::new();
581	    for token in input.split(',') {
582	        let key = token.trim().to_string();
583	        if key.is_empty() {
584	            bail!("key sequence contains an empty token (check for trailing commas)");
585	        }
586	        actions.push(KeyAction { key, dwell_ms: None, gap_ms: None });
587	    }
588	
589	    Ok(actions)
590	}
