7	/// Send a command to the running daemon via the UDS socket.
8	pub fn send_command(req: ControlRequest) -> Result<ControlResponse> {
9	    let socket_path = get_socket_path()?;
10	
11	    let mut stream = UnixStream::connect(&socket_path)
12	        .with_context(|| format!("Failed to connect to daemon at {}. Is it running?", socket_path.display()))?;
13	
14	    let req_json = serde_json::to_string(&req)?;
15	    stream.write_all(req_json.as_bytes())?;
16	    stream.write_all(b"\n")?;
17	
18	    let mut reader = BufReader::new(stream);
19	    let mut response_line = String::new();
20	    reader.read_line(&mut response_line)?;
21	
22	    let response: ControlResponse = serde_json::from_str(&response_line)
23	        .with_context(|| format!("Failed to parse daemon response: {response_line}"))?;
24	
25	    Ok(response)
26	}
27	
28	/// Query live daemon status. Returns `None` if the daemon is not running.
29	pub fn query_status() -> Option<DaemonStatus> {
30	    match send_command(ControlRequest::Status) {
31	        Ok(ControlResponse::StatusData(status)) => Some(status),
32	        _ => None,
33	    }
34	}
35	
36	/// Returns true if the daemon socket exists (daemon likely running).
37	pub fn is_daemon_running() -> bool {
38	    get_socket_path().map(|p| p.exists()).unwrap_or(false)
39	}
40	
41	// Client-side path resolution: uses find_runtime_file, which is read-only and returns an
42	// error if the socket doesn't exist (i.e. the daemon isn't running). The directory-creating
43	// counterpart lives in control/mod.rs.
44	fn get_socket_path() -> Result<PathBuf> {
45	    let xdg = xdg::BaseDirectories::with_prefix("vibe-attack");
46	    xdg.find_runtime_file("vibe-attack.sock")
47	        .context("Could not find daemon socket. Is the daemon running?")
48	}
